const DIRS = [
  { dx: 1, dy: 0 },
  { dx: -1, dy: 0 },
  { dx: 0, dy: 1 },
  { dx: 0, dy: -1 }
];

export function canonicalKey(from, to) {
  const a = { x: from.x, y: from.y };
  const b = { x: to.x, y: to.y };
  const firstIsA = a.x < b.x || (a.x === b.x && a.y <= b.y);
  const p1 = firstIsA ? a : b;
  const p2 = firstIsA ? b : a;
  return `${p1.x},${p1.y},${p2.x},${p2.y}`;
}

export function parseKey(key) {
  const [x1, y1, x2, y2] = key.split(',').map((n) => Number(n));
  return { x1, y1, x2, y2 };
}

function isHorizontal(seg) {
  return seg.y1 === seg.y2;
}

function isVertical(seg) {
  return seg.x1 === seg.x2;
}

function segsCross(segA, segB) {
  // Cross only if one is horizontal and the other vertical, and they intersect at a point
  // that is strictly inside both segments (not at endpoints).
  const a = segA;
  const b = segB;
  if (isHorizontal(a) && isVertical(b)) {
    const ay = a.y1;
    const axMin = Math.min(a.x1, a.x2);
    const axMax = Math.max(a.x1, a.x2);

    const bx = b.x1;
    const byMin = Math.min(b.y1, b.y2);
    const byMax = Math.max(b.y1, b.y2);

    const intersects = bx > axMin && bx < axMax && ay > byMin && ay < byMax;
    return intersects;
  }
  if (isVertical(a) && isHorizontal(b)) {
    return segsCross(b, a);
  }
  return false;
}

function hasCrossing(bridges, candidateKey) {
  const cand = parseKey(candidateKey);
  for (const [key, count] of bridges.entries()) {
    if (count <= 0) continue;
    if (key === candidateKey) continue;
    const seg = parseKey(key);
    if (segsCross(cand, seg)) return true;
  }
  return false;
}

function buildIslandByXY(islands) {
  const m = new Map();
  for (const isl of islands) {
    m.set(`${isl.x},${isl.y}`, isl);
  }
  return m;
}

function isClearLine(islandsByXY, from, to) {
  if (from.x !== to.x && from.y !== to.y) return false;
  const dx = Math.sign(to.x - from.x);
  const dy = Math.sign(to.y - from.y);
  let x = from.x + dx;
  let y = from.y + dy;
  while (x !== to.x || y !== to.y) {
    if (islandsByXY.has(`${x},${y}`)) return false;
    x += dx;
    y += dy;
  }
  return true;
}

export function computeCurrentCounts(islands, bridges) {
  const counts = new Map();
  for (const isl of islands) counts.set(isl.id, 0);

  for (const [key, n] of bridges.entries()) {
    if (n <= 0) continue;
    const { x1, y1, x2, y2 } = parseKey(key);
    const a = islands.find((i) => i.x === x1 && i.y === y1);
    const b = islands.find((i) => i.x === x2 && i.y === y2);
    if (!a || !b) continue;
    counts.set(a.id, (counts.get(a.id) ?? 0) + n);
    counts.set(b.id, (counts.get(b.id) ?? 0) + n);
  }

  return counts;
}

export function canAddBridge(islands, bridges, from, to, delta) {
  if (!from || !to) return { valid: false, error: 'Invalid islands' };
  if (from.id === to.id) return { valid: false, error: 'Cannot connect island to itself' };
  if (from.x !== to.x && from.y !== to.y) {
    return { valid: false, error: 'Cannot connect non-adjacent islands' };
  }

  const islandsByXY = buildIslandByXY(islands);
  if (!isClearLine(islandsByXY, from, to)) {
    return { valid: false, error: 'Cannot connect non-adjacent islands' };
  }

  const key = canonicalKey(from, to);
  const existing = bridges.get(key) ?? 0;
  const next = existing + delta;

  if (next < 0) {
    return { valid: false, error: 'Invalid bridge change' };
  }
  if (next > 2) {
    return { valid: false, error: 'Max 2 bridges per pair' };
  }

  // Crossing check only relevant if adding (increasing count)
  if (delta > 0) {
    if (hasCrossing(bridges, key)) {
      return { valid: false, error: 'Bridges would cross' };
    }
  }

  // Island counts constraint (only for adding)
  if (delta > 0) {
    const counts = computeCurrentCounts(islands, bridges);
    const fromCount = counts.get(from.id) ?? 0;
    const toCount = counts.get(to.id) ?? 0;
    if (fromCount + delta > from.value || toCount + delta > to.value) {
      return { valid: false, error: 'Island would exceed its number' };
    }
  }

  return { valid: true, error: null };
}

export function checkConnectivity(islands, bridges) {
  if (islands.length === 0) return true;

  const byXY = buildIslandByXY(islands);
  const adj = new Map();
  for (const isl of islands) adj.set(isl.id, []);

  for (const [key, n] of bridges.entries()) {
    if (n <= 0) continue;
    const { x1, y1, x2, y2 } = parseKey(key);
    const a = byXY.get(`${x1},${y1}`);
    const b = byXY.get(`${x2},${y2}`);
    if (!a || !b) continue;
    adj.get(a.id).push(b.id);
    adj.get(b.id).push(a.id);
  }

  const startId = islands[0].id;
  const q = [startId];
  const seen = new Set([startId]);
  while (q.length) {
    const cur = q.shift();
    for (const nxt of adj.get(cur) || []) {
      if (!seen.has(nxt)) {
        seen.add(nxt);
        q.push(nxt);
      }
    }
  }

  return seen.size === islands.length;
}

export function isVictory(islands, bridges) {
  // Counts must match
  const counts = computeCurrentCounts(islands, bridges);
  for (const isl of islands) {
    if ((counts.get(isl.id) ?? 0) !== isl.value) return false;
  }

  // No crossings
  const keys = [...bridges.entries()].filter(([, n]) => n > 0).map(([k]) => k);
  for (let i = 0; i < keys.length; i++) {
    for (let j = i + 1; j < keys.length; j++) {
      const a = parseKey(keys[i]);
      const b = parseKey(keys[j]);
      if (segsCross(a, b)) return false;
    }
  }

  // Connected
  return checkConnectivity(islands, bridges);
}

export function findNextIsland(islands, fromId, dir) {
  const from = islands.find((i) => i.id === fromId);
  if (!from) return fromId;

  let best = null;
  for (const isl of islands) {
    if (isl.id === from.id) continue;
    const dx = isl.x - from.x;
    const dy = isl.y - from.y;

    if (dir.dx !== 0) {
      if (dy !== 0) continue;
      if (Math.sign(dx) !== dir.dx) continue;
      const dist = Math.abs(dx);
      if (!best || dist < best.dist) best = { id: isl.id, dist };
    } else {
      if (dx !== 0) continue;
      if (Math.sign(dy) !== dir.dy) continue;
      const dist = Math.abs(dy);
      if (!best || dist < best.dist) best = { id: isl.id, dist };
    }
  }
  return best ? best.id : fromId;
}

export { DIRS };
EOF

cat > src/App.jsx <<'EOF'
import React, { useEffect, useMemo, useRef, useState } from 'react';
import { puzzles } from './data/puzzles';
import {
  DIRS,
  canAddBridge,
  canonicalKey,
  computeCurrentCounts,
  findNextIsland,
  isVictory
} from './utils/hashiLogic';

const GRID = 40;
const SVG_W = 800;
const SVG_H = 600;

function keyToEndpoints(islandsByXY, key) {
  const [x1, y1, x2, y2] = key.split(',').map(Number);
  const a = islandsByXY.get(`${x1},${y1}`);
  const b = islandsByXY.get(`${x2},${y2}`);
  return { a, b, x1, y1, x2, y2 };
}

function App() {
  const [puzzleName, setPuzzleName] = useState('Easy');
  const puzzle = useMemo(
    () => puzzles.find((p) => p.name === puzzleName) || puzzles[0],
    [puzzleName]
  );

  const [bridges, setBridges] = useState(() => new Map());
  const [selectedIslandId, setSelectedIslandId] = useState(null);
  const [cursorIslandId, setCursorIslandId] = useState(0);
  const [error, setError] = useState(null);
  const [victory, setVictory] = useState(false);

  const islands = puzzle.islands;
  const islandsById = useMemo(() => {
    const m = new Map();
    for (const isl of islands) m.set(isl.id, isl);
    return m;
  }, [islands]);

  const islandsByXY = useMemo(() => {
    const m = new Map();
    for (const isl of islands) m.set(`${isl.x},${isl.y}`, isl);
    return m;
  }, [islands]);

  const counts = useMemo(() => computeCurrentCounts(islands, bridges), [islands, bridges]);

  const pendingSelectionRef = useRef({ cursorIslandId, selectedIslandId });
  useEffect(() => {
    pendingSelectionRef.current = { cursorIslandId, selectedIslandId };
  }, [cursorIslandId, selectedIslandId]);

  // Reset cursor to island 0 after any puzzle change
  useEffect(() => {
    setBridges(new Map());
    setSelectedIslandId(null);
    setCursorIslandId(0);
    setError(null);
    setVictory(false);
  }, [puzzleName]);

  // Recompute victory when bridges change
  useEffect(() => {
    setVictory(isVictory(islands, bridges));
  }, [islands, bridges]);

  useEffect(() => {
    function onKeyDown(e) {
      // Global listeners: do not require focused node
      const { cursorIslandId: cur, selectedIslandId: sel } = pendingSelectionRef.current;

      if (e.key === 'Escape') {
        setSelectedIslandId(null);
        return;
      }

      if (e.key === 'Enter') {
        if (sel == null) {
          setSelectedIslandId(cur);
        } else {
          if (sel === cur) {
            // Keep selection as-is
            return;
          }
          toggleBridgeByIslands(sel, cur);
        }
        return;
      }

      let dir = null;
      if (e.key === 'ArrowLeft') dir = { dx: -1, dy: 0 };
      if (e.key === 'ArrowRight') dir = { dx: 1, dy: 0 };
      if (e.key === 'ArrowUp') dir = { dx: 0, dy: -1 };
      if (e.key === 'ArrowDown') dir = { dx: 0, dy: 1 };
      if (!dir) return;

      e.preventDefault();
      const nextId = findNextIsland(islands, cur, dir);
      setCursorIslandId(nextId);
    }

    window.addEventListener('keydown', onKeyDown);
    return () => window.removeEventListener('keydown', onKeyDown);
  }, [islands]);

  function toggleBridgeByIslands(fromId, toId) {
    const from = islandsById.get(fromId);
    const to = islandsById.get(toId);
    if (!from || !to) return;

    setBridges((prev) => {
      const next = new Map(prev);
      const key = canonicalKey(from, to);
      const existing = next.get(key) ?? 0;
      const desired = existing === 0 ? 1 : existing === 1 ? 2 : 0;
      const delta = desired - existing;

      // If removing (delta<0), allow directly (no need for canAddBridge)
      if (delta < 0) {
        if (desired === 0) next.delete(key);
        else next.set(key, desired);
        // valid move
        setError(null);
        setSelectedIslandId(null);
        setCursorIslandId(0);
        return next;
      }

      if (delta === 0) {
        setSelectedIslandId(null);
        return next;
      }

      const res = canAddBridge(islands, next, from, to, delta);
      if (!res.valid) {
        // Error must reset in-progress selection so next click starts fresh
        setError(res.error);
        setSelectedIslandId(null);
        return prev;
      }

      // apply
      if (desired === 0) next.delete(key);
      else next.set(key, desired);

      setError(null);
      setSelectedIslandId(null);
      setCursorIslandId(0);
      return next;
    });
  }

  function onIslandClick(islandId) {
    setCursorIslandId(islandId);
    if (selectedIslandId == null) {
      setSelectedIslandId(islandId);
      return;
    }
    if (selectedIslandId === islandId) {
      // Deselect
      setSelectedIslandId(null);
      return;
    }
    toggleBridgeByIslands(selectedIslandId, islandId);
  }

  function removeBridgePairByKey(key) {
    setBridges((prev) => {
      if (!prev.has(key)) return prev;
      const next = new Map(prev);
      next.delete(key);
      setError(null);
      setSelectedIslandId(null);
      setCursorIslandId(0);
      return next;
    });
  }

  function renderBridgeLines() {
    const lines = [];
    for (const [key, n] of bridges.entries()) {
      if (n <= 0) continue;
      const { a, b, x1, y1, x2, y2 } = keyToEndpoints(islandsByXY, key);
      if (!a || !b) continue;

      const px1 = x1 * GRID;
      const py1 = y1 * GRID;
      const px2 = x2 * GRID;
      const py2 = y2 * GRID;

      const isH = y1 === y2;
      const isV = x1 === x2;

      const baseStyle = {
        stroke: '#0f0',
        strokeWidth: 4,
        strokeLinecap: 'round'
      };

      const attachHandlers = (lineKeySuffix) => ({
        onClick: (e) => {
          if (e.ctrlKey) {
            e.preventDefault();
            removeBridgePairByKey(key);
          }
        },
        onContextMenu: (e) => {
          e.preventDefault();
          removeBridgePairByKey(key);
        },
        'data-bridge': `${key}:${lineKeySuffix}`
      });

      if (n === 1) {
        lines.push(
          <line
            key={`b-${key}-single`}
            x1={px1}
            y1={py1}
            x2={px2}
            y2={py2}
            {...attachHandlers('single')}
            style={baseStyle}
          />
        );
      } else if (n === 2) {
        // Parallel offset in pixels
        const offset = 6;
        const dx = isH ? 0 : offset;
        const dy = isV ? 0 : offset;

        // For horizontal line, offset in Y; for vertical line, offset in X
        if (isH) {
          lines.push(
            <line
              key={`b-${key}-d1`}
              x1={px1}
              y1={py1 - offset}
              x2={px2}
              y2={py2 - offset}
              {...attachHandlers('double1')}
              style={baseStyle}
            />
          );
          lines.push(
            <line
              key={`b-${key}-d2`}
              x1={px1}
              y1={py1 + offset}
              x2={px2}
              y2={py2 + offset}
              {...attachHandlers('double2')}
              style={baseStyle}
            />
          );
        } else if (isV) {
          lines.push(
            <line
              key={`b-${key}-d1`}
              x1={px1 - offset}
              y1={py1}
              x2={px2 - offset}
              y2={py2}
              {...attachHandlers('double1')}
              style={baseStyle}
            />
          );
          lines.push(
            <line
              key={`b-${key}-d2`}
              x1={px1 + offset}
              y1={py1}
              x2={px2 + offset}
              y2={py2}
              {...attachHandlers('double2')}
              style={baseStyle}
            />
          );
        } else {
          // Shouldn't happen
          lines.push(
            <line
              key={`b-${key}-fallback`}
              x1={px1 + dx}
              y1={py1 + dy}
              x2={px2 + dx}
              y2={py2 + dy}
              {...attachHandlers('fallback')}
              style={baseStyle}
            />
          );
        }
      }
    }
    return lines;
  }

  const cursorIsland = islandsById.get(cursorIslandId) || islands[0];
  const cursorPx = cursorIsland
    ? { x: cursorIsland.x * GRID, y: cursorIsland.y * GRID }
    : { x: 0, y: 0 };

  return (
    <div className="app-root">
      <div className="hud">
        <label>
          Puzzle:{' '}
          <select
            value={puzzleName}
            onChange={(e) => {
              // fully reset bridges/selection/error/victory in same update via effect
              setPuzzleName(e.target.value);
            }}
          >
            <option value="Easy">Easy</option>
            <option value="Medium">Medium</option>
            <option value="Hard">Hard</option>
          </select>
        </label>
        <button
          onClick={() => {
            setBridges(new Map());
            setSelectedIslandId(null);
            setCursorIslandId(0);
            setError(null);
            setVictory(false);
          }}
        >
          Reset
        </button>
        <div className="status">
          {selectedIslandId != null ? `Selected: ${selectedIslandId}` : 'Selected: (none)'}
        </div>
      </div>

      {error ? <div className="error-message">{error}</div> : null}
      {victory ? <div className="victory-banner">SOLVED!</div> : null}

      <svg
        width={SVG_W}
        height={SVG_H}
        viewBox={`0 0 ${SVG_W} ${SVG_H}`}
        className="board"
      >
        {/* Bridges */}
        {renderBridgeLines()}

        {/* Cursor (must not be a circle) */}
        <rect
          x={cursorPx.x - 18}
          y={cursorPx.y - 18}
          width={36}
          height={36}
          fill="none"
          stroke="#0f0"
          strokeWidth={2}
          strokeDasharray="4 3"
          className="cursor"
        />

        {/* Islands */}
        {islands.map((isl) => {
          const px = isl.x * GRID;
          const py = isl.y * GRID;
          const isSelected = selectedIslandId === isl.id;
          const curCount = counts.get(isl.id) ?? 0;
          return (
            <g key={isl.id} className="island" onClick={() => onIslandClick(isl.id)}>
              <circle
                cx={px}
                cy={py}
                r={16}
                fill="black"
                stroke={isSelected ? '#9f9' : '#0f0'}
                strokeWidth={isSelected ? 4 : 2}
              />
              <text
                x={px}
                y={py + 5}
                textAnchor="middle"
                fontSize="16"
                fill="#0f0"
              >
                {isl.value}
              </text>
              <text
                x={px}
                y={py + 28}
                textAnchor="middle"
                fontSize="10"
                fill="#0f0"
              >
                {curCount}/{isl.value}
              </text>
            </g>
          );
        })}
      </svg>
    </div>
  );
}

export default App;
EOF

